mapper.select:
SELECT
FROM tb_pmb_plan_list a LEFT JOIN tb_pmb_plan_zzim b ON b.prod_id = a.id WHERE sale_status = 1 AND disp_yn = 1 AND a.id IN
#{planid}
ORDER BY sale_price LIMIT #{offset}, #{recordSize}

SELECT a.id, a.user_mng_id, a.prod_id, a.create_date FROM tb_pmb_plan_zzim a LEFT JOIN tb_pmb_plan_list b ON a.prod_id = b.id WHERE b.disp_yn = 1 AND b.sale_status = 1
AND user_mng_id = #{userMngId}
AND prod_id = #{planListId}
ORDER BY create_date DESC

SELECT count(1) FROM tb_pmb_plan_zzim a LEFT JOIN tb_pmb_plan_list b ON a.prod_id = b.id WHERE b.disp_yn = 1 AND b.sale_status = 1
AND user_mng_id = #{userMngId}
AND prod_id = #{planListId}

mapper.delete:
DELETE FROM tb_pmb_plan_zzim
WHERE user_mng_id = #{userMngId}
AND prod_id = #{prodId}
